final:
module RefModule (
	input clk,
	input reset,
	input enable,
	output reg [6:0] data_out
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		data_out <= 7'b0000000;
	else if (enable)
		data_out <= data_out >> 1;
end

endmodule
